import React, { useState, useEffect, useCallback } from 'react';

const SETS = {
  lower: 'abcdefghijklmnopqrstuvwxyz',
  upper: 'ABCDEFGHIJKLMNOPQRSTUVWXYZ',
  digits: '0123456789',
  symbols: '!@#$%^&*()-_=+[]{}',
};

const LABELS = ['Very weak', 'Weak', 'Fair', 'Good', 'Strong', 'Very strong'];
const COLORS = ['#dc2626', '#ea580c', '#d97706', '#ca8a04', '#16a34a', '#15803d'];

export default function PasswordGenerator() {
  const [length, setLength] = useState(16);
  const [opts, setOpts] = useState({ lower: true, upper: true, digits: true, symbols: false });
  const [password, setPassword] = useState('');

  const generate = useCallback(() => {
    const pool = Object.keys(SETS).filter((k) => opts[k]).map((k) => SETS[k]).join('');
    if (!pool) {
      setPassword('');
      return;
    }
    let out = '';
    for (let i = 0; i < length; i++) {
      out += pool[Math.floor(Math.random() * pool.length)];
    }
    setPassword(out);
  }, [length, opts]);

  useEffect(() => {
    generate();
  }, [generate]);

  const variety = ['lower', 'upper', 'digits', 'symbols'].filter((k) => opts[k]).length;
  const score = Math.min(5, variety - 1 + (length >= 16 ? 2 : length >= 12 ? 1 : 0));

  const toggle = (k) => setOpts((o) => ({ ...o, [k]: !o[k] }));

  return (
    <div style={{ maxWidth: 420 }}>
      <div style={{ display: 'flex', gap: 8, alignItems: 'center' }}>
        <code style={{ flex: 1, padding: '10px 12px', background: '#f3f4f6', borderRadius: 6, fontSize: 15, wordBreak: 'break-all' }}>
          {password || '— enable a character set —'}
        </code>
        <button onClick={generate} style={{ padding: '10px 14px', cursor: 'pointer' }}>↻</button>
      </div>

      {password && (
        <div style={{ marginTop: 8, color: COLORS[score], fontWeight: 600 }}>{LABELS[score]}</div>
      )}

      <label style={{ display: 'block', marginTop: 16 }}>
        Length: {length}
        <input type="range" min="6" max="32" value={length} onChange={(e) => setLength(Number(e.target.value))} style={{ width: '100%' }} />
      </label>

      <div style={{ display: 'flex', flexWrap: 'wrap', gap: 12, marginTop: 8 }}>
        {Object.keys(SETS).map((k) => (
          <label key={k} style={{ display: 'flex', gap: 6, textTransform: 'capitalize' }}>
            <input type="checkbox" checked={opts[k]} onChange={() => toggle(k)} />
            {k}
          </label>
        ))}
      </div>
    </div>
  );
}

