import { Component, OnInit } from '@angular/core';
import { NgModule } from '@angular/core';
import { BrowserModule } from '@angular/platform-browser';

@Component({
  selector: 'app-password-generator',
  template: `
    <div style="max-width: 420px;">
      <div style="display: flex; gap: 8px; align-items: center;">
        <code style="flex: 1; padding: 10px 12px; background: #f3f4f6; border-radius: 6px; font-size: 15px; word-break: break-all;">{{ password || '— enable a character set —' }}</code>
        <button (click)="generate()" style="padding: 10px 14px; cursor: pointer;">↻</button>
      </div>

      <div *ngIf="password" [style.color]="colors[score]" style="margin-top: 8px; font-weight: 600;">{{ labels[score] }}</div>

      <label style="display: block; margin-top: 16px;">
        Length: {{ length }}
        <input type="range" min="6" max="32" [value]="length" (input)="length = toNum($any($event.target).value); generate()" style="width: 100%;" />
      </label>

      <div style="display: flex; flex-wrap: wrap; gap: 12px; margin-top: 8px;">
        <label *ngFor="let k of keys" style="display: flex; gap: 6px; text-transform: capitalize;">
          <input type="checkbox" [checked]="opts[k]" (change)="opts[k] = !opts[k]; generate()" />
          {{ k }}
        </label>
      </div>
    </div>
  `,
})
export class PasswordGeneratorComponent implements OnInit {
  length = 16;
  opts: Record<string, boolean> = { lower: true, upper: true, digits: true, symbols: false };
  password = '';

  readonly SETS: Record<string, string> = {
    lower: 'abcdefghijklmnopqrstuvwxyz',
    upper: 'ABCDEFGHIJKLMNOPQRSTUVWXYZ',
    digits: '0123456789',
    symbols: '!@#$%^&*()-_=+[]{}',
  };
  readonly keys = Object.keys(this.SETS);
  readonly labels = ['Very weak', 'Weak', 'Fair', 'Good', 'Strong', 'Very strong'];
  readonly colors = ['#dc2626', '#ea580c', '#d97706', '#ca8a04', '#16a34a', '#15803d'];

  ngOnInit(): void {
    this.generate();
  }

  toNum(v: string): number {
    return Number(v);
  }

  generate(): void {
    const pool = this.keys.filter((k) => this.opts[k]).map((k) => this.SETS[k]).join('');
    if (!pool) {
      this.password = '';
      return;
    }
    let out = '';
    for (let i = 0; i < this.length; i++) {
      out += pool[Math.floor(Math.random() * pool.length)];
    }
    this.password = out;
  }

  get score(): number {
    const variety = this.keys.filter((k) => this.opts[k]).length;
    return Math.min(5, variety - 1 + (this.length >= 16 ? 2 : this.length >= 12 ? 1 : 0));
  }
}

@Component({
  selector: 'app-root',
  template: `
    <div style="font-family: sans-serif; padding: 20px;">
      <h1>Password Generator Demo</h1>
      <app-password-generator></app-password-generator>
    </div>
  `,
})
export class AppComponent {}

@NgModule({
  declarations: [AppComponent, PasswordGeneratorComponent],
  imports: [BrowserModule],
  bootstrap: [AppComponent],
})
export class AppModule {}
